from dataclasses import dataclass, field
from typing import Optional

@dataclass
class Task:
    task_id: str
    name: str
    duration_weeks: int
    predecessors: list[str] = field(default_factory=list)
    # Computed by CPM forward/backward pass
    early_start: int = 0
    early_finish: int = 0
    late_start: int = 0
    late_finish: int = 0

    @property
    def total_float(self) -> int:
        return self.late_start - self.early_start

    @property
    def is_critical(self) -> bool:
        return self.total_float == 0


def compute_cpm(tasks: dict[str, Task]) -> dict[str, Task]:
    """Run forward and backward pass CPM on a task graph."""
    # Topological sort (Kahn's algorithm)
    from collections import deque
    in_degree = {tid: 0 for tid in tasks}
    successors: dict[str, list[str]] = {tid: [] for tid in tasks}
    for tid, task in tasks.items():
        for pred in task.predecessors:
            successors[pred].append(tid)
            in_degree[tid] += 1

    queue = deque(tid for tid, deg in in_degree.items() if deg == 0)
    topo_order = []
    while queue:
        tid = queue.popleft()
        topo_order.append(tid)
        for succ in successors[tid]:
            in_degree[succ] -= 1
            if in_degree[succ] == 0:
                queue.append(succ)

    # Forward pass
    for tid in topo_order:
        task = tasks[tid]
        if not task.predecessors:
            task.early_start = 0
        else:
            task.early_start = max(tasks[p].early_finish for p in task.predecessors)
        task.early_finish = task.early_start + task.duration_weeks

    # Project end = max EF of all tasks
    project_end = max(t.early_finish for t in tasks.values())

    # Backward pass
    for tid in reversed(topo_order):
        task = tasks[tid]
        if not successors[tid]:
            task.late_finish = project_end
        else:
            task.late_finish = min(tasks[s].late_start for s in successors[tid])
        task.late_start = task.late_finish - task.duration_weeks

    return tasks

from datetime import date, timedelta

@dataclass
class TaskProgress:
    task_id: str
    projected_finish: date    # updated by the team
    baseline_finish: date     # locked at PI planning

    @property
    def slip_days(self) -> int:
        return max(0, (self.projected_finish - self.baseline_finish).days)

    @property
    def slip_weeks(self) -> int:
        return self.slip_days // 7


def weekly_critical_path_scan(
    tasks: dict[str, Task],
    progress: list[TaskProgress],
    context: str = "",
) -> str:
    """Scan for slipping critical-path tasks and generate a risk brief."""
    client = anthropic.Anthropic()
    critical_ids = {tid for tid, t in tasks.items() if t.is_critical}

    slipping_critical = [
        p for p in progress
        if p.task_id in critical_ids and p.slip_weeks > 0
    ]

    if not slipping_critical:
        return "All critical path tasks on track. No action needed."

    slip_lines = "\n".join(
        f"- {tasks[p.task_id].name}: {p.slip_weeks}w slip "
        f"(baseline {p.baseline_finish} → projected {p.projected_finish})"
        for p in slipping_critical
    )

    message = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=400,
        messages=[{"role": "user", "content": f"""
Weekly critical-path scan. Program context: {context}

Slipping critical-path tasks:
{slip_lines}

Write a brief status message (≤120 words) for the program Slack channel:
1. Total schedule impact in weeks
2. Tasks at immediate risk
3. Recommended action this week
4. Escalation needed? (yes/no and to whom)
"""}],
    )
    return message.content[0].text

def near_critical_tasks(
    tasks: dict[str, Task],
    threshold_weeks: int = 2,
) -> list[Task]:
    """Return tasks with float ≤ threshold (but > 0) — near-critical."""
    return sorted(
        [t for t in tasks.values() if 0 < t.total_float <= threshold_weeks],
        key=lambda t: t.total_float,
    )

def float_burn_rate(
    task: Task,
    weeks_elapsed: int,
    float_consumed: int,
) -> dict:
    """Assess how quickly a task is burning through its float budget."""
    remaining_float = task.total_float - float_consumed
    weeks_to_critical = remaining_float  # float=0 → task joins critical path
    return {
        "task_id": task.task_id,
        "task_name": task.name,
        "original_float": task.total_float,
        "float_remaining": remaining_float,
        "weeks_elapsed": weeks_elapsed,
        "float_consumed_per_week": float_consumed / max(weeks_elapsed, 1),
        "weeks_to_critical": weeks_to_critical,
        "alert": remaining_float <= 1,
    }

